  /// Shared execution pipeline: interceptors -> send -> deserialize.
  Future<ApiResult<T>> _execute<T>(
    ApiRequest request, {
    required T Function(ApiResponse) onSuccess,
  }) async {
    var req = request;
    try {
      for (final interceptor in _config.interceptors) {
        req = await interceptor.onRequest(req);
      }

      var response = _config.timeout != null
          ? await _config.client.send(req).timeout(_config.timeout!)
          : await _config.client.send(req);

      for (final interceptor in _config.interceptors) {
        response = await interceptor.onResponse(response);
      }

      if (response.isSuccessful) {
        return ApiSuccess(
          onSuccess(response),
          statusCode: response.statusCode,
          headers: response.headers,
        );
      }
      return ApiError(
        statusCode: response.statusCode,
        rawBody: response.body,
        headers: response.headers,
      );
    } catch (e, st) {
      for (final interceptor in _config.interceptors) {
        try {
          final recovered = await interceptor.onError(e, st, req);
          if (recovered.isSuccessful) {
            return ApiSuccess(
              onSuccess(recovered),
              statusCode: recovered.statusCode,
              headers: recovered.headers,
            );
          }
          return ApiError(
            statusCode: recovered.statusCode,
            rawBody: recovered.body,
            headers: recovered.headers,
          );
        } catch (_) {
          // Interceptor couldn't handle it, continue to next or fall through
        }
      }
      return ApiException(e, st);
    }
